  vocab:[["piece", "׀Ā"], ["hole", "ࣀĀ"], ["middle", "ҸĀ"], ["isolate", "ϜĀ"], ["part", "सĀ"], ["object", "׌Ā"], ["concentrate on ~", "ˤĀ"], ["distract", "ɸĀ"], ["whole", "بĀ"], ["useful", "شĀ"], ["tool", "॔Ā"], ["focus", "ܴĀ"], ["organise", "ȌĀ"], ["observation", "ಠĀ"], ["support", "͈Ā"], ["hesitant", "ƌĀ"], ["boundary (to ~)", "ȘĀ"], ["find", "঄Ā"], ["keep track of ~", "ְĀ"], ["bring A back to B", "ǔĀ"], ["look back", "྄Ā"], ["size", "ীĀ"], ["rest", "ৄĀ"], ["visual", "ՐĀ"], ["information", "ೀĀ"], ["field of vision", "ठĀ"]],
  question:"다음 글의 밑줄 친 부분 중, 문맥상 낱말의 쓰임이 적절하지 않은 것은?",
